const n="/api/roles";async function e(){const o=await fetch(n);if(!o.ok)throw new Error("Error al obtener roles");return o.json()}async function a(o){const r=await fetch(`${n}/${o}`);if(!r.ok)throw new Error("Rol no encontrado");return r.json()}async function s(o){const r=await fetch(n,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(o)});if(!r.ok)throw new Error("Error al crear rol");return r.json()}async function c(o,r){const t=await fetch(`${n}/${o}`,{method:"PUT",headers:{"Content-Type":"application/json"},body:JSON.stringify(r)});if(!t.ok)throw new Error("Error al actualizar rol");return t.json()}export{a,s as c,e as g,c as u};
